examples.goldenOutput:
thread MyThread
  features
    Input: in event data port Integer;
    Output: out data port Boolean;
  properties
    Dispatch_Protocol => Periodic;
    Period => 10 ms;
end MyThread;

thread implementation MyThread.impl
  subcomponents
    Sub: subprogram MySubprogram;
  connections
    conn: port Input -> Sub.param;
end MyThread.impl;

processor P1
  features
    BusPort: in bus port;
end P1;
processor P2
  features
    BusPort: in bus port;
end P2;
bus B
end B;
system implementation Top.impl
  subcomponents
    P1_inst: processor P1.impl;
    P2_inst: processor P2.impl;
    B_inst: bus B.impl;
  connections
    bus P1_inst.BusPort -> B_inst;
    bus P2_inst.BusPort -> B_inst;
end Top.impl;

thread T
  features
    E: in event port;
  properties
    Queue_Size => 5;
    Overflow_Handling_Protocol => DropOldest;
end T;

thread T
  flows
    OutFlow: flow source OutPort;
end T;
thread implementation T.impl
  subcomponents
    Sub: subprogram S;
  connections
    port Sub.Result -> OutPort;
  flows
    OutFlow: flow path Sub.Result -> OutPort;
end T.impl;
